public void insert()
{
    ETGACFParameters acfParameters = ETGACFParameters::find();
    LedgerJournalTrans ledgerJournalTrans;
    select firstOnly OffsetDefaultDimension
        from ledgerJournalTrans
            where ledgerJournalTrans.Voucher == this.Voucher;

    if (ledgerJournalTrans.OffsetDefaultDimension && acfParameters.Vertical)
    {
        this.ETGVertical = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValueCodeOnlyETG(ledgerJournalTrans.OffsetDefaultDimension,acfParameters.Vertical);
    }
    next insert();

}
